from __future__ import annotations

import json
from typing import TYPE_CHECKING, Any

from lfx.custom.custom_component.component_with_cache import ComponentWithCache
from lfx.io import BoolInput, MessageTextInput, MultilineInput, Output
from lfx.schema.dataframe import DataFrame
from lfx.schema.message import Message
from lfx.services.cache.utils import CacheMiss

if TYPE_CHECKING:
    from pymongo.collection import Collection
    from pymongo.mongo_client import MongoClient


class MongoDBComponent(ComponentWithCache):
    """A MongoDB data source component."""

    display_name = "MongoDB"
    description = "Executes find and aggregate MongoDB queries."
    icon = "MongoDB"
    name = "MongoDBComponent"
    metadata = {"keywords": ["mongodb", "database", "query", "db", "fetch", "nosql"]}

    def __init__(self, **kwargs) -> None:
        super().__init__(**kwargs)
        self.client: "MongoClient | None" = None

    def maybe_create_client(self) -> None:
        if self.database_url == "":
            return
        if self._shared_component_cache:
            cached_client = self._shared_component_cache.get(self.database_url)
            if not isinstance(cached_client, CacheMiss):
                self.client = cached_client
                return
            self.log("Connecting to MongoDB")
        try:
            from pymongo import MongoClient
        except ImportError as e:
            msg = "Please install pymongo to use MongoDBComponent."
            raise ImportError(msg) from e
        try:
            self.client = MongoClient(self.database_url)
            self.client.admin.command("ping")
        except Exception as e:
            msg = f"An error occurred while connecting to MongoDB: {e}"
            raise ValueError(msg) from e
        if self._shared_component_cache:
            self._shared_component_cache.set(self.database_url, self.client)

    inputs = [
        MessageTextInput(name="database_url", display_name="Database URL", required=True),
        MessageTextInput(name="database_name", display_name="Database Name", required=True),
        MessageTextInput(name="collection_name", display_name="Collection Name", required=True),
        MultilineInput(
            name="query",
            display_name="MongoDB Query",
            tool_mode=True,
            required=True,
            info=(
                "MongoDB query as JSON. Supports either a plain filter document, an aggregation pipeline list, "
                "or an object with operation/filter/projection/sort/limit/skip/pipeline keys."
            ),
        ),
        BoolInput(name="include_id", display_name="Include _id", value=True, tool_mode=True, advanced=True),
        BoolInput(
            name="add_error",
            display_name="Add Error",
            value=False,
            tool_mode=True,
            info="If True, the error will be added to the result",
            advanced=True,
        ),
    ]

    outputs = [
        Output(display_name="Result Table", name="run_mongodb_query", method="run_mongodb_query"),
    ]

    def _get_collection(self) -> "Collection":
        self.maybe_create_client()
        if self.client is None:
            msg = "Database URL is required."
            raise ValueError(msg)
        return self.client[self.database_name][self.collection_name]

    def _parse_query(self) -> dict[str, Any] | list[dict[str, Any]]:
        try:
            parsed_query = json.loads(self.query)
        except json.JSONDecodeError as e:
            msg = f"MongoDB query must be valid JSON: {e}"
            raise ValueError(msg) from e
        if not isinstance(parsed_query, dict | list):
            msg = "MongoDB query must be a JSON object or JSON array."
            raise ValueError(msg)
        return parsed_query

    def _normalize_document(self, document: dict[str, Any]) -> dict[str, Any]:
        normalized = json.loads(json.dumps(document, default=str))
        if not self.include_id:
            normalized.pop("_id", None)
        return normalized

    def _parse_sort(self, sort_value: Any) -> list[tuple[str, int]] | None:
        if sort_value is None:
            return None
        if isinstance(sort_value, dict):
            return [(str(field), int(direction)) for field, direction in sort_value.items()]
        if isinstance(sort_value, list):
            parsed_sort = []
            for item in sort_value:
                if not isinstance(item, list | tuple) or len(item) != 2:
                    msg = "Sort list entries must be [field, direction]."
                    raise ValueError(msg)
                parsed_sort.append((str(item[0]), int(item[1])))
            return parsed_sort
        msg = "Sort must be a JSON object or list of [field, direction]."
        raise ValueError(msg)

    def _extract_filter(self, query: dict[str, Any]) -> dict[str, Any]:
        query_options = {"operation", "filter", "projection", "sort", "limit", "skip", "pipeline"}
        fallback_filter = {k: v for k, v in query.items() if k not in query_options}
        if "filter" in query:
            if not isinstance(query["filter"], dict):
                msg = "The 'filter' value must be a JSON object."
                raise ValueError(msg)
            mongo_filter = dict(query["filter"])
            mongo_filter.update(fallback_filter)
            return mongo_filter
        if query_options.intersection(query):
            return fallback_filter
        return query

    def _execute_find(self, collection: "Collection", query: dict[str, Any]) -> list[dict[str, Any]]:
        mongo_filter = self._extract_filter(query)
        projection = query.get("projection")
        if projection is not None and not isinstance(projection, dict):
            msg = "The 'projection' value must be a JSON object."
            raise ValueError(msg)

        cursor = collection.find(mongo_filter, projection)

        sort_value = self._parse_sort(query.get("sort"))
        if sort_value:
            cursor = cursor.sort(sort_value)

        skip = query.get("skip")
        if skip is not None:
            cursor = cursor.skip(int(skip))

        limit = query.get("limit")
        if limit is not None:
            cursor = cursor.limit(int(limit))

        return [self._normalize_document(document) for document in cursor]

    def _execute_aggregate(self, collection: "Collection", pipeline: list[dict[str, Any]]) -> list[dict[str, Any]]:
        if not isinstance(pipeline, list):
            msg = "The aggregation pipeline must be a JSON array."
            raise ValueError(msg)
        return [self._normalize_document(document) for document in collection.aggregate(pipeline)]

    def __execute_query(self) -> list[dict[str, Any]]:
        collection = self._get_collection()
        parsed_query = self._parse_query()

        try:
            if isinstance(parsed_query, list):
                return self._execute_aggregate(collection, parsed_query)

            operation = str(parsed_query.get("operation", "find")).lower()
            if operation == "find":
                return self._execute_find(collection, parsed_query)
            if operation == "aggregate":
                pipeline = parsed_query.get("pipeline")
                if pipeline is None:
                    msg = "The 'aggregate' operation requires a 'pipeline' key."
                    raise ValueError(msg)
                return self._execute_aggregate(collection, pipeline)

            msg = f"Unsupported MongoDB operation: {operation}"
            raise ValueError(msg)
        except ValueError:
            raise
        except Exception as e:
            msg = f"An error occurred while running the MongoDB Query: {e}"
            self.log(msg)
            raise ValueError(msg) from e

    def build_component(self) -> Message:
        error = None
        try:
            result_data = self.__execute_query()
            result = json.dumps(result_data, indent=2)
            self.status = result
        except ValueError as e:
            result = str(e)
            self.status = result
            error = repr(e)

        if self.add_error and error is not None:
            result = f"{result}\n\nError: {error}\n\nQuery: {self.query}"
        elif error is not None:
            result = self.query

        return Message(text=result)

    def run_mongodb_query(self) -> DataFrame:
        result = self.__execute_query()
        df_result = DataFrame(result)
        self.status = df_result
        return df_result
